const event = $input.first().json.body;

// Only process checkout.session.completed
if (event.type !== 'checkout.session.completed') {
  return [{json: {status: 'ignored', reason: event.type}}];
}

const session = event.data.object;
const metadata = session.metadata || {};

// Verify this is Enterprise tier
if (metadata.tier !== 'enterprise') {
  return [{json: {status: 'ignored', reason: 'not enterprise tier'}}];
}

return [{
  json: {
    client_id: metadata.client_id || session.customer_details?.email?.split('@')[0]?.toUpperCase() || 'UNKNOWN',
    customer_email: session.customer_details?.email,
    customer_name: session.customer_details?.name,
    stripe_subscription_id: session.subscription,
    stripe_session_id: session.id,
    billing_period: metadata.billing || 'monthly',
    tier: metadata.tier,
    compliance: metadata.compliance || 'SOC2',
    locations: (metadata.locations || 'ord').split(','),
    status: 'checkout_complete'
  }
}];
